            >
              Add Section
            </button>
            <button
              type="button"
              onClick={() => onSaveDraft('unchecked')}
              className="px-5 py-2 rounded-xl bg-indigo-500 hover:bg-indigo-400 text-slate-950 border border-indigo-300 text-[10px] font-black uppercase cursor-pointer"
            >
              Save Draft
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

