  const studentProgress = user.role === 'student' ? loadStudentProgressSnapshot(localStorage, user.username) : null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/80 backdrop-blur-md p-4">
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 max-w-lg w-full shadow-2xl relative text-left space-y-6 transform scale-98 transition-transform duration-300">
        <button
          type="button"
          onClick={onClose}
          className="absolute top-4 right-4 bg-slate-950 hover:bg-slate-850 text-slate-500 hover:text-slate-200 border border-slate-800 rounded-full w-8 h-8 flex items-center justify-center font-bold transition-all cursor-pointer"
        >
          ✕
        </button>

        <div className="flex items-center gap-3 pb-4 border-b border-slate-805">
          <span className="text-3xl">👤</span>
          <div>
            <h3 className="text-lg font-black text-slate-100">Chi Tiết Học Viên @{user.username}</h3>
            <p className="text-[10px] text-slate-500">
              Đăng ký lúc: {user.createdAt ? new Date(user.createdAt).toLocaleString('vi-VN') : 'Không rõ'}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-slate-950 p-3 rounded-2xl border border-slate-850 text-xs">
            <span className="text-[10px] text-slate-500 font-bold uppercase block mb-1">Tên hiển thị</span>
            <span className="font-extrabold text-slate-200">{user.displayName || user.username}</span>
          </div>
          <div className="bg-slate-950 p-3 rounded-2xl border border-slate-850 text-xs">
            <span className="text-[10px] text-slate-500 font-bold uppercase block mb-1">Vai Trò</span>
            <span className="font-extrabold text-orange-400 capitalize">
              {user.role === 'admin' ? 'Quản trị viên' : user.role === 'parent' ? 'Phụ huynh' : 'Học sinh'}
            </span>
          </div>
          <div className="bg-slate-950 p-3 rounded-2xl border border-slate-850 text-xs">
            <span className="text-[10px] text-slate-500 font-bold uppercase block mb-1">Mục tiêu</span>
            <span className="font-extrabold text-slate-200">{user.role === 'student' ? `Band ${user.targetBand}` : '-'}</span>
          </div>
          <div className="bg-slate-950 p-3 rounded-2xl border border-slate-850 text-xs">
            <span className="text-[10px] text-slate-500 font-bold uppercase block mb-1">Ví Xu Cá Hồi</span>
            <span className="font-extrabold text-orange-400 font-mono">
              {studentProgress ? `${studentProgress.coins} 🐟` : '-'}
            </span>
          </div>
        </div>

        {user.role === 'student' && (
          <div className="space-y-4">
            <div>
              <span className="text-[10px] font-black uppercase tracking-wider text-slate-400 block mb-2">
                Bơm / Trừ Ví Xu Cá Hồi
              </span>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => onAdjustCoins(user.username, 50)}
                  className="flex-1 py-2 bg-slate-950 hover:bg-emerald-950/60 border border-slate-800 hover:border-emerald-900 rounded-xl text-xs font-bold text-slate-400 hover:text-emerald-400 cursor-pointer transition-all"
                >
                  🐟 +50 Xu
                </button>
                <button
                  type="button"
                  onClick={() => onAdjustCoins(user.username, 100)}
                  className="flex-1 py-2 bg-slate-950 hover:bg-emerald-950/60 border border-slate-800 hover:border-emerald-900 rounded-xl text-xs font-bold text-slate-400 hover:text-emerald-400 cursor-pointer transition-all"
                >
                  🐟 +100 Xu
                </button>
                <button
                  type="button"
                  onClick={() => onAdjustCoins(user.username, -50)}
                  className="flex-1 py-2 bg-slate-950 hover:bg-rose-950/60 border border-slate-800 hover:border-rose-900 rounded-xl text-xs font-bold text-slate-400 hover:text-rose-400 cursor-pointer transition-all"
                >
                  🪓 -50 Xu
                </button>
              </div>
            </div>

            <div>
              <span className="text-[10px] font-black uppercase tracking-wider text-slate-400 block mb-2">
                Phân Quyền Các Khoá Học Assigned
              </span>
              <div className="flex flex-wrap gap-2">
                {(['math', 'sat', 'ielts', 'cae', 'cpe'] as const).map((track) => {
                  const isAssigned = (user.assignedTracks || []).includes(track);

                  return (
                    <button
                      type="button"
                      key={track}
                      onClick={() => {
                        let nextTracks = [...(user.assignedTracks || [])];
                        if (nextTracks.includes(track)) {
                          nextTracks = nextTracks.filter((assignedTrack) => assignedTrack !== track);
                        } else {
                          nextTracks.push(track);
                        }
                        onUpdateUserTracks(user.username, nextTracks);
                      }}
                      className={`px-2.5 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all cursor-pointer border ${
                        isAssigned
                          ? 'bg-orange-500/20 border-orange-500 text-orange-400'
                          : 'bg-slate-950 border-slate-850 text-slate-500 hover:text-slate-350'
                      }`}
                    >
                      {track.toUpperCase()}
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        <div className="flex gap-3 pt-4 border-t border-slate-800 justify-end">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 bg-slate-950 hover:bg-slate-850 border border-slate-800 text-slate-400 text-xs font-extrabold uppercase rounded-xl cursor-pointer"
          >
            Đóng
          </button>
        </div>
      </div>
    </div>
  );
}

import type { Dispatch, SetStateAction } from 'react';
import type { LocalUser } from '@miuprep/db';

type UserSummary = Omit<LocalUser, 'passwordHash'>;
type RoleFilter = 'all' | 'admin' | 'parent' | 'student';
type StatusFilter = 'all' | 'pending' | 'approved' | 'rejected';

interface AdminUsersPanelProps {
  users: UserSummary[];
  roleFilter: RoleFilter;
  setRoleFilter: Dispatch<SetStateAction<RoleFilter>>;
  statusFilter: StatusFilter;
  setStatusFilter: Dispatch<SetStateAction<StatusFilter>>;
  onOpenUserDetail: (username: string) => void | Promise<void>;
  onUpdateStatus: (username: string, nextStatus: 'approved' | 'rejected') => void | Promise<void>;
  onDeleteUser: (username: string) => void | Promise<void>;
}

export default function AdminUsersPanel({
  users,
  roleFilter,
  setRoleFilter,
  statusFilter,
  setStatusFilter,
  onOpenUserDetail,
  onUpdateStatus,
  onDeleteUser,
}: AdminUsersPanelProps) {
  const filteredUsers = users.filter((user) => {
    if (roleFilter !== 'all' && user.role !== roleFilter) return false;
    const status = user.status || 'pending';
    if (statusFilter !== 'all' && status !== statusFilter) return false;
    return true;
  });

  return (
    <section className="bg-slate-900/60 border border-slate-800 rounded-3xl p-6 max-w-5xl mx-auto shadow-xl">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-6 pb-4 border-b border-slate-800">
        <h3 className="text-sm font-black text-slate-350 uppercase tracking-widest">
          👥 DANH SÁCH TÀI KHOẢN ({users.length})
        </h3>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-1.5">
            <span className="text-[10px] text-slate-500 font-bold uppercase">Vai trò:</span>
            <select
              value={roleFilter}
              onChange={(event) => setRoleFilter(event.target.value as RoleFilter)}
              className="bg-slate-950 border border-slate-850 text-slate-300 rounded-lg px-2 py-1 text-[10px] font-bold outline-none cursor-pointer"
            >
              <option value="all">Tất cả</option>
              <option value="admin">Quản trị</option>
              <option value="parent">Phụ huynh</option>
              <option value="student">Học sinh</option>
            </select>
          </div>

          <div className="flex items-center gap-1.5">
            <span className="text-[10px] text-slate-500 font-bold uppercase">Duyệt:</span>
            <select
              value={statusFilter}
              onChange={(event) => setStatusFilter(event.target.value as StatusFilter)}
              className="bg-slate-950 border border-slate-850 text-slate-300 rounded-lg px-2 py-1 text-[10px] font-bold outline-none cursor-pointer"
            >
              <option value="all">Tất cả</option>
              <option value="pending">Chờ duyệt</option>
              <option value="approved">Đã duyệt</option>
              <option value="rejected">Bị từ chối</option>
            </select>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto rounded-2xl border border-slate-850">
        <table className="w-full border-collapse text-left text-xs text-slate-300">
          <thead>
            <tr className="bg-slate-950 border-b border-slate-850 text-slate-500 font-bold">
              <th className="p-4">Người dùng</th>
              <th className="p-4">Liên hệ</th>
              <th className="p-4">Vai trò</th>
              <th className="p-4">Trạng thái</th>
              <th className="p-4">Ngày đăng ký</th>
              <th className="p-4 text-center">Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.length === 0 ? (
              <tr>
                <td colSpan={6} className="p-8 text-center text-slate-500 italic">
                  Không tìm thấy tài khoản nào phù hợp...
                </td>
              </tr>
            ) : (
              filteredUsers.map((user) => {
                const status = user.status || 'pending';

                return (
                  <tr key={user.id} className="border-b border-slate-900 hover:bg-slate-900/30 transition-colors">
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                        <span
                          className={`w-8 h-8 rounded-full flex items-center justify-center font-black uppercase text-[10px] ${
                            user.role === 'admin'
                              ? 'bg-purple-900/40 text-purple-300'
                              : user.role === 'parent'
                                ? 'bg-orange-900/40 text-orange-300'
                                : 'bg-slate-800 text-slate-300'
                          }`}
                        >
                          {user.username.slice(0, 2)}
                        </span>
                        <div className="flex flex-col text-left">
                          <span className="font-extrabold text-sm text-white">{user.displayName || user.username}</span>
                          <span className="text-[10px] text-slate-500 font-mono">@{user.username}</span>
                        </div>
                      </div>
                    </td>
                    <td className="p-4 font-semibold text-slate-300 font-mono">
                      {user.contactInfo || <span className="text-slate-650 italic">Không có</span>}
                    </td>
                    <td className="p-4">
                      <span
                        className={`text-[9px] font-black px-2.5 py-0.5 rounded-full border uppercase tracking-wider ${
                          user.role === 'admin'
                            ? 'bg-purple-950/70 border-purple-900 text-purple-400'
                            : user.role === 'parent'
                              ? 'bg-orange-950/70 border-orange-900 text-orange-400'
                              : 'bg-slate-950/60 border-slate-850 text-slate-400'
                        }`}
                      >
                        {user.role === 'admin' ? 'Admin' : user.role === 'parent' ? 'Phụ huynh' : 'Học sinh'}
                      </span>
                    </td>
                    <td className="p-4 font-bold">
                      <span
                        className={`text-[9px] font-black px-2.5 py-0.5 rounded-full border uppercase tracking-wider ${
                          status === 'approved'
                            ? 'bg-emerald-950/75 border-emerald-900 text-emerald-400'
                            : status === 'rejected'
                              ? 'bg-rose-950/75 border-rose-900 text-rose-400'
                              : 'bg-amber-950/75 border-amber-900 text-amber-400 animate-pulse'
                        }`}
                      >
                        {status === 'approved' ? '✓ Đã duyệt' : status === 'rejected' ? '❌ Bị từ chối' : '⏳ Chờ duyệt'}
                      </span>
                    </td>
                    <td className="p-4 text-slate-500 font-mono">
                      {user.createdAt ? new Date(user.createdAt).toLocaleDateString('vi-VN') : '-'}
                    </td>
                    <td className="p-4">
                      <div className="flex items-center justify-center gap-2">
                        <button
                          type="button"
                          onClick={() => onOpenUserDetail(user.username)}
                          className="px-2 py-1 rounded bg-slate-950 hover:bg-indigo-950/60 text-slate-500 hover:text-indigo-400 border border-slate-800 hover:border-indigo-900 transition-all cursor-pointer font-bold text-xs"
                          title="Xem chi tiết & Điều chỉnh"
                        >
                          🔍
                        </button>
                        {status !== 'approved' && (
                          <button
                            type="button"
                            onClick={() => onUpdateStatus(user.username, 'approved')}
                            className="px-2.5 py-1 rounded bg-emerald-700 hover:bg-emerald-600 text-white font-extrabold text-[10px] uppercase transition-all border-0 cursor-pointer"
                            title="Duyệt tài khoản"
                          >
                            Duyệt ✓
                          </button>
                        )}
                        {status !== 'rejected' && (
                          <button
                            type="button"
                            onClick={() => onUpdateStatus(user.username, 'rejected')}
                            className="px-2.5 py-1 rounded bg-rose-950 hover:bg-rose-900 text-rose-400 font-extrabold text-[10px] uppercase transition-all border-0 cursor-pointer"
                            title="Từ chối tài khoản"
                          >
                            Từ chối ❌
                          </button>
                        )}
                        <button
                          type="button"
                          onClick={() => onDeleteUser(user.username)}
                          className="px-2 py-1 rounded bg-slate-950 hover:bg-slate-900 hover:text-red-400 text-slate-500 border border-slate-800 transition-all cursor-pointer"
                          title="Xóa vĩnh viễn"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </section>
  );
}

import { useMemo, useState } from 'react';
import type { LocalUser } from '@miuprep/db';
import type { LearningEventRecord } from '@miuprep/learning';
import {
  buildEnglishCoreRemediationPlan,
  recommendEnglishCoreLessonTemplates,
  type EnglishCoreLessonTemplate,
  type EnglishCoreRemediationPlan,
  type LessonTemplateStage,
} from '../lib/lessonTemplates';
import type { LessonTemplateAction } from '../lib/studentProgress';
import {
  buildLearnerSnapshotFromLiveEvents,
  normalizeAssignedTracks,
  type PortalTrackInfo,
} from './UnifiedLearnerDashboard';

interface EnglishCoreLessonTemplatePanelProps {
  currentUser: LocalUser;
  tracks: PortalTrackInfo[];
  fishCoins: number;
  mouseTrapsCount: number;
  learningEvents?: LearningEventRecord[];
  onOpenPractice: () => void;
  onOpenTutor: () => void;
  onTemplateAction?: (template: EnglishCoreLessonTemplate, action: LessonTemplateAction) => void;
}

const ENGLISH_TRACK_IDS = new Set(['ielts', 'cpe', 'cae', 'sat']);

export default function EnglishCoreLessonTemplatePanel({
  currentUser,
  tracks,
  fishCoins,
  mouseTrapsCount,
  learningEvents = [],
  onOpenPractice,
  onOpenTutor,
  onTemplateAction,
}: EnglishCoreLessonTemplatePanelProps) {
  const assignedTrackIds = useMemo(() => normalizeAssignedTracks(currentUser), [currentUser]);
  const activeTracks = useMemo(
    () => tracks.filter((track) => assignedTrackIds.includes(track.id)),
    [assignedTrackIds, tracks],
  );
  const activeEnglishTracks = activeTracks.filter((track) => ENGLISH_TRACK_IDS.has(track.id));
  const snapshot = useMemo(
    () => buildLearnerSnapshotFromLiveEvents(currentUser, activeTracks, learningEvents, fishCoins, mouseTrapsCount),
    [activeTracks, currentUser, fishCoins, learningEvents, mouseTrapsCount],
  );

  const englishSummary = snapshot.programSummaries.find((summary) => ENGLISH_TRACK_IDS.has(summary.track.id));
  const englishNextStep = snapshot.learningPath.steps.find((step) => step.domainId === 'english_core');
  const weakConceptIds = uniqueIds([
    ...snapshot.recommendation.conceptIds,
    ...(englishNextStep?.scope === 'concept' ? [englishNextStep.id] : []),
  ]).filter((id) => id.startsWith('eng.'));
  const weakSkillIds = uniqueIds([
    ...snapshot.recommendation.skillIds,
    ...(englishNextStep?.scope === 'skill' ? [englishNextStep.id] : []),
  ]).filter((id) => id.startsWith('eng.'));
  const weakLabel = englishSummary?.weakestLabel || englishNextStep?.label || 'English Core repair';
  const remediationPlan = useMemo(
    () =>
      buildEnglishCoreRemediationPlan({
        weakConceptIds,
        weakSkillIds,
        weakLabel,
        errorText: snapshot.recommendation.reason,
        limit: 6,
      }),
    [snapshot.recommendation.reason, weakConceptIds, weakLabel, weakSkillIds],
  );
  const recommendations = remediationPlan.templates.length
    ? remediationPlan.templates
    : recommendEnglishCoreLessonTemplates({ weakConceptIds, weakSkillIds, weakLabel, limit: 6 });
  const [selectedTemplateId, setSelectedTemplateId] = useState(recommendations[0]?.template.id || '');
  const selectedRecommendation = recommendations.find((item) => item.template.id === selectedTemplateId) || recommendations[0];

  if (!activeEnglishTracks.length) return null;
  if (!selectedRecommendation) return null;

  const selectedTemplate = selectedRecommendation.template;

  return (
    <section className="bg-slate-950/70 border border-sky-500/20 rounded-3xl p-5 sm:p-6 shadow-2xl shadow-sky-950/20 text-left space-y-6">
      <div className="flex flex-col lg:flex-row lg:items-start lg:justify-between gap-4">
        <div className="max-w-3xl">
          <div className="flex flex-wrap items-center gap-2">
            <span className="text-[10px] font-black uppercase tracking-[0.16em] text-sky-300 bg-sky-500/10 border border-sky-500/30 px-2 py-1 rounded">
              English Core
            </span>
            <span className="text-[10px] font-black uppercase tracking-[0.16em] text-slate-400 bg-slate-900 border border-slate-800 px-2 py-1 rounded">
              Reusable for IELTS/CAE/CPE/SAT
            </span>
          </div>
          <h2 className="text-xl sm:text-2xl font-black text-slate-100 mt-3 mb-2">English repair loop theo Knowledge Graph</h2>
          <p className="text-xs sm:text-sm text-slate-400 leading-relaxed m-0">
            English Core tach grammar, vocabulary, collocation, reading, listening, writing va speaking thanh lesson loop ngan.
            Moi loop co transfer task de hoc sinh dua kien thuc vao de thi nhanh hon.
          </p>
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-2 xl:grid-cols-4 gap-2 lg:min-w-[520px]">
          <LessonMetric label="Weak focus" value={compactLabel(weakLabel)} />
          <LessonMetric label="Error lens" value={compactLabel(remediationPlan.errorLens.label)} />
          <LessonMetric label="Target" value={`${selectedTemplate.masteryTarget}%`} />
          <LessonMetric label="Minutes" value={String(selectedTemplate.estimatedMinutes)} />
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-[0.95fr_1.55fr] gap-5">
        <div className="space-y-3">
          {recommendations.map((recommendation, index) => {
            const template = recommendation.template;
            const isSelected = template.id === selectedTemplate.id;
            return (
              <button
                key={template.id}
                type="button"
                onClick={() => setSelectedTemplateId(template.id)}
                className={`w-full text-left border rounded-2xl p-4 transition-all cursor-pointer ${
                  isSelected
                    ? 'bg-sky-500/10 border-sky-400/50 shadow-lg shadow-sky-950/30'
                    : 'bg-slate-900/60 border-slate-800 hover:border-sky-500/30'
                }`}
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${isSelected ? 'text-sky-300' : 'text-slate-500'}`}>
                      Rank {index + 1} - {recommendation.matchReason}
                    </span>
                    <h3 className="text-sm sm:text-base font-black text-slate-100 mt-1 mb-1">{template.title}</h3>
                    <p className="text-xs text-slate-400 leading-relaxed m-0">{template.focus}</p>
                  </div>
                  <span className="text-[10px] font-black text-sky-300 bg-sky-500/10 border border-sky-500/20 rounded-full px-2 py-1 shrink-0">
                    {template.estimatedMinutes}m
                  </span>
                </div>
                <div className="grid grid-cols-3 gap-2 mt-4">
                  <TinyStat label="Area" value={compactLabel(template.area)} />
                  <TinyStat label="Exams" value={String(template.examLayers.length)} />
                  <TinyStat label="Skills" value={String(template.skillIds.length)} />
                </div>
              </button>
            );
          })}
        </div>

        <EnglishTemplateDetail
          template={selectedTemplate}
          matchReason={selectedRecommendation.matchReason}
          remediationPlan={remediationPlan}
          onOpenPractice={onOpenPractice}
          onOpenTutor={onOpenTutor}
          onTemplateAction={onTemplateAction}
        />
      </div>
    </section>
  );
}

