      .forEach((stepId) => onDailyStepCompleted?.(stepId));
    if (!dailyPlan.isCompleted) onDailyPlanCompleted?.();
  };

  const resetToday = () => {
    setCompletedStepIds([]);
    persistDailyPlanCompletedSteps(localStorage, currentUser.username, [], dateKey);
  };

